"""
IDA Pro / Ghidra style .so decompiler
Finds anti-cheat functions, hook points, and bypass locations
"""

import subprocess
import re
import json
from collections import defaultdict

class SODecompiler:
    def __init__(self, so_path):
        self.path = so_path
        self.functions = []
        self.strings = []
        self.symbols = []
        self.anti_cheat_funcs = []

    def extract_symbols(self):
        """Get exported functions like IDA Functions window"""
        try:
            result = subprocess.run(['nm', '-D', self.path], capture_output=True, text=True)
            for line in result.stdout.split('\n'):
                if ' T ' in line or ' W ' in line:
                    parts = line.split()
                    if len(parts) >= 3:
                        addr, type_, name = parts[0], parts[1], ' '.join(parts[2:])
                        self.symbols.append({
                            'address': addr,
                            'type': type_,
                            'name': name
                        })
        except:
            pass
        return self

    def extract_strings(self):
        """Get strings like IDA Strings window"""
        try:
            result = subprocess.run(['strings', '-n', '8', self.path], capture_output=True, text=True)
            anti_cheat_keywords = [
                'cheat', 'hack', 'emulator', 'debug', 'root', 'bypass', 'integrity',
                'tamper', 'modify', 'inject', 'hook', 'frida', 'xposed', 'magisk',
                'su', 'superuser', 'anogs', 'protection', 'security', 'verify'
            ]

            for line in result.stdout.split('\n'):
                line_lower = line.lower()
                is_suspicious = any(kw in line_lower for kw in anti_cheat_keywords)
                if is_suspicious:
                    self.strings.append({
                        'string': line,
                        'suspicious': True
                    })
        except:
            pass
        return self

    def disassemble_functions(self):
        """Disassemble like IDA View-A"""
        try:
            result = subprocess.run(['objdump', '-d', '-M', 'intel', self.path], 
                                  capture_output=True, text=True)

            current_func = None
            anti_patterns = [
                r'call.*ptrace', r'call.*fopen.*su', r'call.*stat.*su',
                r'call.*getenv.*emulator', r'test.*eax.*eax', r'jz.*'
            ]

            for line in result.stdout.split('\n'):
                if re.match(r'^[0-9a-f]+ <.*>:', line):
                    func_name = re.findall(r'<(.+)>:', line)[0]
                    current_func = {
                        'name': func_name,
                        'address': line.split()[0],
                        'instructions': [],
                        'suspicious': False
                    }
                    self.functions.append(current_func)
                elif current_func and re.match(r'^\s+[0-9a-f]+:', line):
                    current_func['instructions'].append(line.strip())

            # Mark anti-cheat functions
            for func in self.functions:
                func_lower = func['name'].lower()
                if any(x in func_lower for x in ['cheat', 'hack', 'protect', 'check', 'verify', 
                                                  'integrity', 'anti', 'detect', 'root', 'debug']):
                    func['suspicious'] = True
                    self.anti_cheat_funcs.append(func)

        except:
            pass
        return self

    def find_bypass_points(self):
        """Find patchable locations for bypasses"""
        bypasses = []

        for func in self.anti_cheat_funcs:
            addr = func.get('address', '0')
            bypasses.append({
                'function': func['name'],
                'address': addr,
                'patch_type': 'NOP',
                'description': f'Return 0 to disable {func["name"]}',
                'original': 'call detection_logic',
                'patch': 'xor eax,eax; ret'
            })

        return bypasses

    def generate_report(self):
        """IDA-style disassembly report"""
        report = {
            'file': self.path,
            'total_functions': len(self.functions),
            'anti_cheat_functions': self.anti_cheat_funcs,
            'suspicious_strings': self.strings,
            'bypass_points': self.find_bypass_points(),
            'hook_candidates': [
                {'name': 'JNI_OnLoad', 'purpose': 'Entry point hook'},
                {'name': 'pthread_create', 'purpose': 'Thread hook'},
                {'name': 'fopen', 'purpose': 'File access hook'},
                {'name': 'stat', 'purpose': 'File stat hook'},
                {'name': 'ptrace', 'purpose': 'Debug detection hook'}
            ]
        }
        return report

if __name__ == '__main__':
    import sys
    if len(sys.argv) > 1:
        analyzer = SODecompiler(sys.argv[1])
        analyzer.extract_symbols().extract_strings().disassemble_functions()
        report = analyzer.generate_report()
        print(json.dumps(report, indent=2))
